<!-- MODAL KEYBOARD SHORTCUTS -->
<!-- Contract marker: Shortcut Safeguards -->
<!-- Contract marker: Single-key page shortcuts are suppressed while typing in inputs and while dialogs are open. -->
<dialog id='modal_help' data-dialog-close-on-backdrop='true' aria-labelledby='modal_help_title' aria-describedby='modal_help_aria modal_help_meta'>
  <div class='modal_aria visually_hidden'>
    <span id='modal_help_aria'>__KEYBOARD_SHORTCUTS_MODAL_ARIA__</span>
  </div>
  <div class='modal_meta visually_hidden'>
    <span id='modal_help_meta'>__KEYBOARD_SHORTCUTS_MODAL_META__</span>
  </div>
  <section class='modal_header'>
    <button type='button' class='btn btn_close' data-dialog-close='modal_help' aria-label='__CLOSE__'>&times;</button>
    <h2 id='modal_help_title' class='modal_title centered'>__KEYBOARD_SHORTCUTS__</h2>
  </section>
  <section id='modal_help_content' class='modal_content keyboard_shortcuts_layout'>
    <div class='keyboard_shortcuts_panel' role='group' aria-label='__KEYBOARD_SHORTCUTS_SYSTEM_ARIA__'>
      <h3 class='keyboard_shortcuts_panel_title'>__KEYBOARD_SHORTCUTS_SYSTEM_TITLE__</h3>
      <div class='keyboard_shortcuts_table'>
        <div class='keyboard_shortcuts_row' aria-label='__OPEN_CALENDAR_WITH__'><span class='keyboard_shortcuts_label'>__OPEN_CALENDAR__</span><span class='keyboard_shortcuts_keys' data-shortcut-combo='true'><kbd>C</kbd></span></div>
        <div class='keyboard_shortcuts_row' aria-label='__OPEN_EARNINGS_WITH__'><span class='keyboard_shortcuts_label'>__OPEN_EARNINGS__</span><span class='keyboard_shortcuts_keys' data-shortcut-combo='true'><kbd>R</kbd></span></div>
        <div class='keyboard_shortcuts_row'><span class='keyboard_shortcuts_label'>Open Help</span><span class='keyboard_shortcuts_keys' data-shortcut-combo='true'><kbd>H</kbd></span></div>
        <div class='keyboard_shortcuts_row'><span class='keyboard_shortcuts_label'>Open Transparency Hub</span><span class='keyboard_shortcuts_keys' data-shortcut-combo='true'><kbd>N</kbd></span></div>
        <div class='keyboard_shortcuts_row' aria-label='__OPEN_ACCOUNT_WITH__'><span class='keyboard_shortcuts_label'>__OPEN_ACCOUNT__</span><span class='keyboard_shortcuts_keys' data-shortcut-combo='true'><kbd>E</kbd></span></div>
        <div class='keyboard_shortcuts_row' aria-label='__OPEN_ABOUT_WITH__'><span class='keyboard_shortcuts_label'>__OPEN_ABOUT__</span><span class='keyboard_shortcuts_keys' data-shortcut-combo='true'><kbd>A</kbd></span></div>
        <div class='keyboard_shortcuts_row' aria-label='__OPEN_POLICIES_WITH__'><span class='keyboard_shortcuts_label'>__OPEN_POLICIES__</span><span class='keyboard_shortcuts_keys' data-shortcut-combo='true'><kbd>L</kbd></span></div>
        <div class='keyboard_shortcuts_row'><span class='keyboard_shortcuts_label'>__KEYBOARD_SHORTCUTS_TOGGLE_SIDEBAR__</span><span class='keyboard_shortcuts_keys' data-shortcut-combo='true'><kbd>`</kbd></span></div>
        <div class='keyboard_shortcuts_row' aria-label='__OPEN_SHORTCUTS_WITH__'>
          <span class='keyboard_shortcuts_label'>__OPEN_SHORTCUTS__</span>
          <span class='keyboard_shortcuts_keys' data-shortcut-combo='true'><kbd>?</kbd><span class='keyboard_shortcuts_or'>or</span><kbd>Ctrl/Cmd</kbd><span class='keyboard_shortcuts_sep'>+</span><kbd>K</kbd></span>
        </div>
        <div class='keyboard_shortcuts_row' aria-label='Open Editor with Enter'><span class='keyboard_shortcuts_label'>Open Editor</span><span class='keyboard_shortcuts_keys' data-shortcut-combo='true'><kbd>__ENTER_KEY__</kbd></span></div>
      </div>
    </div>

    <div class='keyboard_shortcuts_panel' role='group' aria-label='__KEYBOARD_SHORTCUTS_CALENDAR_ARIA__'>
      <h3 class='keyboard_shortcuts_panel_title'>__CALENDAR__</h3>
      <div class='keyboard_shortcuts_table'>
        <div class='keyboard_shortcuts_row' aria-label='__TOGGLE_CALENDAR_SCREENMODE_WITH__'><span class='keyboard_shortcuts_label'>__TOGGLE_CALENDAR_SCREENMODE__</span><span class='keyboard_shortcuts_keys' data-shortcut-combo='true'><kbd>/</kbd></span></div>
        <div class='keyboard_shortcuts_row' aria-label='__OPEN_DATE_PICKER_WITH__'><span class='keyboard_shortcuts_label'>__OPEN_DATE_PICKER__</span><span class='keyboard_shortcuts_keys' data-shortcut-combo='true'><kbd>&#92;</kbd></span></div>
        <div class='keyboard_shortcuts_row' aria-label='__NAVIGATE_WITH__'><span class='keyboard_shortcuts_label'>__NAVIGATE__</span><span class='keyboard_shortcuts_keys' data-shortcut-combo='true'><kbd>Tab</kbd><kbd>Arrows</kbd><kbd>Home</kbd><kbd>End</kbd></span></div>
        <div class='keyboard_shortcuts_row' aria-label='Change Month with [ or ] or PGDN or PGUP'><span class='keyboard_shortcuts_label'>Change Month</span><span class='keyboard_shortcuts_keys' data-shortcut-combo='true'><kbd>&#91;</kbd><span class='keyboard_shortcuts_or'>or</span><kbd>&#93;</kbd><span class='keyboard_shortcuts_or'>or</span><kbd>PGDN</kbd><kbd>PGUP</kbd></span></div>
        <div class='keyboard_shortcuts_row' aria-label='__COPY_WORK_WITH__'><span class='keyboard_shortcuts_label'>__COPY_WORK__</span><span class='keyboard_shortcuts_keys' data-shortcut-combo='true'><kbd>Ctrl/Cmd</kbd><span class='keyboard_shortcuts_sep'>+</span><kbd>C</kbd></span></div>
        <div class='keyboard_shortcuts_row' aria-label='__PASTE_WORK_WITH__'><span class='keyboard_shortcuts_label'>__PASTE_WORK__</span><span class='keyboard_shortcuts_keys' data-shortcut-combo='true'><kbd>Ctrl/Cmd</kbd><span class='keyboard_shortcuts_sep'>+</span><kbd>V</kbd></span></div>
        <div class='keyboard_shortcuts_row' aria-label='__DELETE_WORK_WITH__'><span class='keyboard_shortcuts_label'>__DELETE_WORK__</span><span class='keyboard_shortcuts_keys' data-shortcut-combo='true'><kbd>__DELETE_KEY__</kbd></span></div>
        <div class='keyboard_shortcuts_row' aria-label='Close Editor with Escape'><span class='keyboard_shortcuts_label'>Close Editor</span><span class='keyboard_shortcuts_keys' data-shortcut-combo='true'><kbd>__ESCAPE_KEY__</kbd></span></div>
      </div>
    </div>
    <section class='keyboard_shortcuts_safeguards' aria-label='__KEYBOARD_SHORTCUTS_SAFEGUARDS_ARIA__'>
      <h3 class='keyboard_shortcuts_panel_title'>__KEYBOARD_SHORTCUTS_SAFEGUARDS_TITLE__</h3>
      <p class='keyboard_shortcuts_help_text'>__KEYBOARD_SHORTCUTS_SAFEGUARDS_TEXT__</p>
    </section>
  </section>
  <section class="modal_footer">
    <div class="modal_controls f_column centered w100 pad_md">
      <form method="dialog" class="centered">
        <button class="modal_close btn_close pad_md" data-dialog-close="modal_help" aria-label="__CLOSE__" autofocus>__CLOSE__</button>
      </form>
      <p class="centered">__HELP_PAGE_TEASER__</p>
    </div>
  </section>
</dialog>
